import { useState, useEffect } from 'react';
import api from './api';

// ── Helpers ──────────────────────────────────────────────────────────────────
const StatusBadge = ({ status }) => {
  const styles = {
    active:    { bg: '#f0fdf4', color: '#16a34a', border: '#bbf7d0' },
    pending:   { bg: '#fffbeb', color: '#d97706', border: '#fde68a' },
    suspended: { bg: '#fef2f2', color: '#dc2626', border: '#fecaca' },
    approved:  { bg: '#f0fdf4', color: '#16a34a', border: '#bbf7d0' },
    rejected:  { bg: '#fef2f2', color: '#dc2626', border: '#fecaca' },
  };
  const s = styles[status] || styles.pending;
  return (
    <span style={{
      background: s.bg, color: s.color, border: `1px solid ${s.border}`,
      padding: '3px 10px', borderRadius: 20,
      fontFamily: "'DM Sans', sans-serif", fontSize: 12, fontWeight: 500,
      textTransform: 'capitalize',
    }}>{status}</span>
  );
};

const Modal = ({ title, onClose, children }) => (
  <div style={{
    position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.45)',
    display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 300,
  }} onClick={onClose}>
    <div style={{
      background: 'white', borderRadius: 20, padding: 32,
      maxWidth: 480, width: '90%', boxShadow: '0 20px 60px rgba(0,0,0,0.2)',
    }} onClick={e => e.stopPropagation()}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <h3 style={{ fontFamily: "'Playfair Display', serif", fontSize: 20, fontWeight: 700 }}>{title}</h3>
        <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: 22, cursor: 'pointer', color: '#888' }}>×</button>
      </div>
      {children}
    </div>
  </div>
);

// ── Main Component ────────────────────────────────────────────────────────────
export default function AdminDashboard({ user, onLogout }) {
  const [tab, setTab] = useState('overview');
  const [owners, setOwners] = useState([]);
  const [venues, setVenues] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [selectedOwner, setSelectedOwner] = useState(null);
  const [selectedVenue, setSelectedVenue] = useState(null);
  const [confirmModal, setConfirmModal] = useState(null);
  const [toast, setToast] = useState('');
  const [error, setError] = useState('');

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(''), 3000); };

  const loadAll = async () => {
    setLoading(true);
    setError('');
    try {
      const [statsRes, ownersRes, venuesRes] = await Promise.all([
        api.get('/admin-api/stats/'),
        api.get('/admin-api/owners/'),
        api.get('/admin-api/venues/'),
      ]);
      setStats(statsRes.data);
      setOwners(ownersRes.data);
      setVenues(venuesRes.data);
    } catch (e) {
      setError('Failed to load data: ' + (e.response?.data?.detail || e.message));
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadAll(); }, []);

  const handleOwnerAction = async (id, action) => {
    try {
      if (action === 'remove') {
        await api.delete(`/admin-api/owners/${id}/`);
        setOwners(prev => prev.filter(o => o.id !== id));
      } else {
        await api.patch(`/admin-api/owners/${id}/`, { action });
        setOwners(prev => prev.map(o => o.id === id
          ? { ...o, status: action === 'suspend' ? 'suspended' : 'active' } : o
        ));
      }
      setConfirmModal(null);
      showToast(action === 'remove' ? 'Owner removed.' : `Owner ${action}d successfully.`);
      loadAll();
    } catch (e) {
      setError(e.response?.data?.detail || 'Action failed.');
      setConfirmModal(null);
    }
  };

  const handleVenueAction = async (id, action) => {
    try {
      if (action === 'remove') {
        await api.delete(`/admin-api/venues/${id}/`);
        setVenues(prev => prev.filter(v => v.id !== id));
      } else {
        await api.patch(`/admin-api/venues/${id}/`, { action });
        setVenues(prev => prev.map(v => v.id === id
          ? { ...v, status: action === 'approve' ? 'approved' : 'rejected' } : v
        ));
      }
      setConfirmModal(null);
      showToast(action === 'approve' ? 'Venue approved!' : action === 'reject' ? 'Venue rejected.' : 'Venue removed.');
      loadAll();
    } catch (e) {
      setError(e.response?.data?.detail || 'Action failed.');
      setConfirmModal(null);
    }
  };

  const filteredOwners = owners.filter(o =>
    o.name?.toLowerCase().includes(search.toLowerCase()) ||
    o.email?.toLowerCase().includes(search.toLowerCase())
  );

  const filteredVenues = venues.filter(v =>
    v.name?.toLowerCase().includes(search.toLowerCase()) ||
    v.owner_name?.toLowerCase().includes(search.toLowerCase())
  );

  const pendingVenues = venues.filter(v => !v.status || v.status === 'pending');

  const tabStyle = (t) => ({
    padding: '9px 20px', borderRadius: 50, cursor: 'pointer',
    fontFamily: "'DM Sans', sans-serif", fontSize: 14, fontWeight: 500,
    border: 'none', transition: 'all 0.15s',
    background: tab === t ? '#1a1a1a' : 'transparent',
    color: tab === t ? 'white' : '#666',
  });

  return (
    <div style={{ fontFamily: "'Georgia', serif", background: '#faf9f7', minHeight: '100vh', color: '#1a1a1a' }}>
      <link href="https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;700;900&family=DM+Sans:wght@300;400;500&display=swap" rel="stylesheet" />

      {/* Navbar */}

      <main style={{ maxWidth: 1000, margin: '0 auto', padding: '40px 24px 100px' }}>
        <h1 style={{ fontFamily: "'Playfair Display', serif", fontSize: 'clamp(1.8rem,3vw,2.4rem)', fontWeight: 700, letterSpacing: '-0.02em', marginBottom: 4 }}>Admin Dashboard</h1>
        <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 15, color: '#888', marginBottom: 32 }}>Manage venue owners, approve listings, and oversee the platform</p>

        {error && (
          <div style={{ marginBottom: 20, padding: '12px 16px', borderRadius: 12, background: '#fef2f2', border: '1px solid #fecaca', color: '#b91c1c', fontFamily: "'DM Sans', sans-serif", fontSize: 13 }}>
            {error}
          </div>
        )}

        {loading ? (
          <p style={{ fontFamily: "'DM Sans', sans-serif", color: '#888' }}>Loading…</p>
        ) : (
          <>
            {/* Stats */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 16, marginBottom: 36 }}>
              {[
                { label: 'Total Venue Owners', value: stats?.total_owners ?? owners.length, sub: 'Registered owners', subColor: '#16a34a' },
                { label: 'Total Venues', value: stats?.total_venues ?? venues.length, sub: 'Active listings', subColor: '#16a34a' },
                { label: 'Pending Approvals', value: stats?.pending_venues ?? pendingVenues.length, sub: 'Awaiting review', subColor: '#d97706' },
                { label: 'Total Bookings', value: stats?.total_bookings ?? 0, sub: 'All time', subColor: '#16a34a' },
              ].map((s, i) => (
                <div key={i} style={{ background: 'white', borderRadius: 16, padding: '20px 24px', boxShadow: '0 2px 12px rgba(0,0,0,0.06)' }}>
                  <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: '#888', marginBottom: 8 }}>{s.label}</div>
                  <div style={{ fontFamily: "'Playfair Display', serif", fontSize: 32, fontWeight: 700, marginBottom: 4 }}>{s.value}</div>
                  <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: s.subColor }}>{s.sub}</div>
                </div>
              ))}
            </div>

            {/* Tabs */}
            <div style={{ display: 'flex', gap: 4, background: '#f0ede8', borderRadius: 50, padding: 4, marginBottom: 28, width: 'fit-content', flexWrap: 'wrap' }}>
              {[
                { key: 'overview', label: 'Overview' },
                { key: 'owners', label: `Venue Owners (${owners.length})` },
                { key: 'venues', label: `Venues (${venues.length})` },
                { key: 'pending', label: `Pending (${pendingVenues.length})` },
              ].map(t => (
                <button key={t.key} style={tabStyle(t.key)} onClick={() => { setTab(t.key); setSearch(''); }}>{t.label}</button>
              ))}
            </div>

            {/* Search */}
            {(tab === 'owners' || tab === 'venues') && (
              <input
                placeholder={tab === 'owners' ? 'Search by name or email…' : 'Search by venue or owner…'}
                value={search} onChange={e => setSearch(e.target.value)}
                style={{ width: '100%', maxWidth: 400, padding: '10px 16px', borderRadius: 50, border: '1px solid #e5e7eb', background: 'white', fontFamily: "'DM Sans', sans-serif", fontSize: 14, marginBottom: 20, outline: 'none' }}
              />
            )}

            {/* ── OVERVIEW ── */}
            {tab === 'overview' && (
              <div>
                {pendingVenues.length > 0 && (
                  <section style={{ marginBottom: 32 }}>
                    <h2 style={{ fontFamily: "'Playfair Display', serif", fontSize: 18, fontWeight: 700, marginBottom: 16 }}>Pending Venue Approvals</h2>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                      {pendingVenues.map(v => (
                        <div key={v.id} style={{ background: 'white', borderRadius: 14, padding: '16px 20px', boxShadow: '0 2px 12px rgba(0,0,0,0.06)', borderLeft: '4px solid #d97706', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <div>
                            <div style={{ fontFamily: "'Playfair Display', serif", fontSize: 15, fontWeight: 700 }}>{v.name}</div>
                            <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: '#888' }}>{v.owner_name} · {v.city} · {v.capacity} guests</div>
                          </div>
                          <div style={{ display: 'flex', gap: 8 }}>
                            <button onClick={() => setConfirmModal({ type: 'venue', id: v.id, action: 'approve' })} style={{ background: '#1a1a1a', color: 'white', border: 'none', padding: '7px 16px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Approve</button>
                            <button onClick={() => setConfirmModal({ type: 'venue', id: v.id, action: 'reject' })} style={{ background: 'transparent', color: '#dc2626', border: '1px solid #fca5a5', padding: '7px 16px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Reject</button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </section>
                )}
                {pendingVenues.length === 0 && (
                  <div style={{ background: 'white', borderRadius: 14, padding: '20px 24px', marginBottom: 32, boxShadow: '0 2px 12px rgba(0,0,0,0.06)', color: '#16a34a', fontFamily: "'DM Sans', sans-serif", fontSize: 14 }}>No pending venue approvals</div>
                )}
                <section>
                  <h2 style={{ fontFamily: "'Playfair Display', serif", fontSize: 18, fontWeight: 700, marginBottom: 16 }}>Recent Venue Owners</h2>
                  <div style={{ background: 'white', borderRadius: 16, overflow: 'hidden', boxShadow: '0 2px 12px rgba(0,0,0,0.06)' }}>
                    {owners.length === 0 && <div style={{ padding: '20px 24px', fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: '#aaa' }}>No venue owners yet.</div>}
                    {owners.slice(0, 5).map((o, i) => (
                      <div key={o.id} style={{ padding: '14px 20px', borderBottom: i < Math.min(owners.length, 5) - 1 ? '1px solid #f3f4f6' : 'none', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div>
                          <span style={{ fontFamily: "'DM Sans', sans-serif", fontWeight: 500, fontSize: 14 }}>{o.name}</span>
                          <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: '#888', marginLeft: 10 }}>{o.email}</span>
                        </div>
                        <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                          <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: '#888' }}>{o.venues} venues</span>
                          <StatusBadge status={o.status} />
                        </div>
                      </div>
                    ))}
                  </div>
                </section>
              </div>
            )}

            {/* ── OWNERS TAB ── */}
            {tab === 'owners' && (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                {filteredOwners.length === 0 && <p style={{ fontFamily: "'DM Sans', sans-serif", color: '#888', textAlign: 'center', padding: '40px 0' }}>No owners found.</p>}
                {filteredOwners.map(o => (
                  <div key={o.id} style={{ background: 'white', borderRadius: 16, padding: '18px 22px', boxShadow: '0 2px 12px rgba(0,0,0,0.06)', display: 'grid', gridTemplateColumns: '1fr auto', gap: 16, alignItems: 'center' }}>
                    <div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 4 }}>
                        <span style={{ fontFamily: "'Playfair Display', serif", fontSize: 16, fontWeight: 700 }}>{o.name}</span>
                        <StatusBadge status={o.status} />
                      </div>
                      <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: '#888' }}>{o.email} · Joined {o.joined} · {o.venues} venue{o.venues !== 1 ? 's' : ''}</div>
                    </div>
                    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                      <button onClick={() => setSelectedOwner(o)} style={{ background: 'transparent', border: '1px solid #e5e7eb', color: '#1a1a1a', padding: '7px 14px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>View</button>
                      {o.status !== 'suspended'
                        ? <button onClick={() => setConfirmModal({ type: 'owner', id: o.id, action: 'suspend' })} style={{ background: 'transparent', border: '1px solid #fde68a', color: '#d97706', padding: '7px 14px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Suspend</button>
                        : <button onClick={() => setConfirmModal({ type: 'owner', id: o.id, action: 'activate' })} style={{ background: 'transparent', border: '1px solid #bbf7d0', color: '#16a34a', padding: '7px 14px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Activate</button>
                      }
                      <button onClick={() => setConfirmModal({ type: 'owner', id: o.id, action: 'remove' })} style={{ background: 'transparent', border: '1px solid #fca5a5', color: '#dc2626', padding: '7px 14px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Remove</button>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* ── VENUES TAB ── */}
            {tab === 'venues' && (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                {filteredVenues.length === 0 && <p style={{ fontFamily: "'DM Sans', sans-serif", color: '#888', textAlign: 'center', padding: '40px 0' }}>No venues found.</p>}
                {filteredVenues.map(v => (
                  <div key={v.id} style={{ background: 'white', borderRadius: 16, padding: '18px 22px', boxShadow: '0 2px 12px rgba(0,0,0,0.06)', display: 'grid', gridTemplateColumns: '1fr auto', gap: 16, alignItems: 'center' }}>
                    <div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 4 }}>
                        <span style={{ fontFamily: "'Playfair Display', serif", fontSize: 16, fontWeight: 700 }}>{v.name}</span>
                        <StatusBadge status={v.status || 'pending'} />
                      </div>
                      <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: '#888' }}>Owner: {v.owner_name} · {v.city} · {v.capacity} guests</div>
                    </div>
                    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                      <button onClick={() => setSelectedVenue(v)} style={{ background: 'transparent', border: '1px solid #e5e7eb', color: '#1a1a1a', padding: '7px 14px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Details</button>
                      {(!v.status || v.status === 'pending') && <>
                        <button onClick={() => setConfirmModal({ type: 'venue', id: v.id, action: 'approve' })} style={{ background: '#1a1a1a', color: 'white', border: 'none', padding: '7px 14px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Approve</button>
                        <button onClick={() => setConfirmModal({ type: 'venue', id: v.id, action: 'reject' })} style={{ background: 'transparent', border: '1px solid #fca5a5', color: '#dc2626', padding: '7px 14px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Reject</button>
                      </>}
                      <button onClick={() => setConfirmModal({ type: 'venue', id: v.id, action: 'remove' })} style={{ background: 'transparent', border: '1px solid #fca5a5', color: '#dc2626', padding: '7px 14px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Remove</button>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* ── PENDING TAB ── */}
            {tab === 'pending' && (
              <div>
                {pendingVenues.length === 0 && <div style={{ textAlign: 'center', padding: '60px 0', color: '#aaa', fontFamily: "'DM Sans', sans-serif" }}> No pending approvals</div>}
                {pendingVenues.map(v => (
                  <div key={v.id} style={{ background: 'white', borderRadius: 16, padding: '20px 24px', boxShadow: '0 2px 12px rgba(0,0,0,0.06)', marginBottom: 12, borderLeft: '4px solid #d97706' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                      <div>
                        <div style={{ fontFamily: "'Playfair Display', serif", fontSize: 17, fontWeight: 700, marginBottom: 6 }}>{v.name}</div>
                        <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: '#888', marginBottom: 12 }}>Owner: {v.owner_name} · {v.city} · {v.capacity} guests</div>
                        <StatusBadge status="pending" />
                      </div>
                      <div style={{ display: 'flex', gap: 8 }}>
                        <button onClick={() => setConfirmModal({ type: 'venue', id: v.id, action: 'approve' })} style={{ background: '#1a1a1a', color: 'white', border: 'none', padding: '9px 20px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 14, cursor: 'pointer' }}> Approve</button>
                        <button onClick={() => setConfirmModal({ type: 'venue', id: v.id, action: 'reject' })} style={{ background: 'transparent', color: '#dc2626', border: '1px solid #fca5a5', padding: '9px 20px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 14, cursor: 'pointer' }}> Reject</button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}
      </main>

      {/* Owner modal */}
      {selectedOwner && (
        <Modal title="Owner Details" onClose={() => setSelectedOwner(null)}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '14px 24px' }}>
            {[['Name', selectedOwner.name], ['Email', selectedOwner.email], ['Joined', selectedOwner.joined], ['Total Venues', selectedOwner.venues], ['Phone', selectedOwner.phone || '—']].map(([label, val]) => (
              <div key={label}>
                <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: '#888', textTransform: 'uppercase', marginBottom: 2 }}>{label}</div>
                <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 14 }}>{val}</div>
              </div>
            ))}
            <div>
              <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: '#888', textTransform: 'uppercase', marginBottom: 2 }}>Status</div>
              <StatusBadge status={selectedOwner.status} />
            </div>
          </div>
          <div style={{ display: 'flex', gap: 10, marginTop: 24 }}>
            {selectedOwner.status !== 'suspended'
              ? <button onClick={() => { setConfirmModal({ type: 'owner', id: selectedOwner.id, action: 'suspend' }); setSelectedOwner(null); }} style={{ background: 'transparent', border: '1px solid #fde68a', color: '#d97706', padding: '9px 20px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Suspend</button>
              : <button onClick={() => { setConfirmModal({ type: 'owner', id: selectedOwner.id, action: 'activate' }); setSelectedOwner(null); }} style={{ background: 'transparent', border: '1px solid #bbf7d0', color: '#16a34a', padding: '9px 20px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Activate</button>
            }
            <button onClick={() => { setConfirmModal({ type: 'owner', id: selectedOwner.id, action: 'remove' }); setSelectedOwner(null); }} style={{ background: 'transparent', border: '1px solid #fca5a5', color: '#dc2626', padding: '9px 20px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Remove Owner</button>
          </div>
        </Modal>
      )}

      {/* Venue modal */}
      {selectedVenue && (
        <Modal title="Venue Details" onClose={() => setSelectedVenue(null)}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '14px 24px' }}>
            {[['Venue Name', selectedVenue.name], ['Owner', selectedVenue.owner_name], ['City', selectedVenue.city], ['Capacity', (selectedVenue.capacity || '—') + ' guests'], ['Price', selectedVenue.price ? `Rs ${selectedVenue.price?.toLocaleString()}` : '—']].map(([label, val]) => (
              <div key={label}>
                <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: '#888', textTransform: 'uppercase', marginBottom: 2 }}>{label}</div>
                <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 14 }}>{val}</div>
              </div>
            ))}
            <div>
              <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: '#888', textTransform: 'uppercase', marginBottom: 2 }}>Status</div>
              <StatusBadge status={selectedVenue.status || 'pending'} />
            </div>
          </div>
          {(!selectedVenue.status || selectedVenue.status === 'pending') && (
            <div style={{ display: 'flex', gap: 10, marginTop: 24 }}>
              <button onClick={() => { setConfirmModal({ type: 'venue', id: selectedVenue.id, action: 'approve' }); setSelectedVenue(null); }} style={{ background: '#1a1a1a', color: 'white', border: 'none', padding: '9px 20px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Approve</button>
              <button onClick={() => { setConfirmModal({ type: 'venue', id: selectedVenue.id, action: 'reject' }); setSelectedVenue(null); }} style={{ background: 'transparent', border: '1px solid #fca5a5', color: '#dc2626', padding: '9px 20px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: 'pointer' }}>Reject</button>
            </div>
          )}
        </Modal>
      )}

      {/* Confirm modal */}
      {confirmModal && (
        <Modal title="Confirm Action" onClose={() => setConfirmModal(null)}>
          <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: '#555', marginBottom: 24 }}>
            Are you sure you want to <strong>{confirmModal.action}</strong> this {confirmModal.type}?
            {confirmModal.action === 'remove' && ' This cannot be undone.'}
          </p>
          <div style={{ display: 'flex', gap: 10, justifyContent: 'center' }}>
            <button onClick={() => confirmModal.type === 'owner' ? handleOwnerAction(confirmModal.id, confirmModal.action) : handleVenueAction(confirmModal.id, confirmModal.action)}
              style={{ background: ['approve', 'activate'].includes(confirmModal.action) ? '#1a1a1a' : '#dc2626', color: 'white', border: 'none', padding: '10px 28px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 14, cursor: 'pointer', textTransform: 'capitalize' }}>
              Yes, {confirmModal.action}
            </button>
            <button onClick={() => setConfirmModal(null)} style={{ background: 'transparent', border: '1px solid #e5e7eb', color: '#1a1a1a', padding: '10px 28px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 14, cursor: 'pointer' }}>Cancel</button>
          </div>
        </Modal>
      )}

      {/* Toast */}
      {toast && (
        <div style={{ position: 'fixed', bottom: 32, left: '50%', transform: 'translateX(-50%)', background: '#1a1a1a', color: 'white', padding: '12px 24px', borderRadius: 50, fontFamily: "'DM Sans', sans-serif", fontSize: 14, zIndex: 400, boxShadow: '0 8px 30px rgba(0,0,0,0.2)' }}>{toast}</div>
      )}
    </div>
  );
}
